module rising_edge_counter(
  input wire clk,
  input wire reset,
  output wire [31:0] count
);

  reg [31:0] count_reg;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset) begin
      count_reg <= 0;
    end else begin
      count_reg <= count_reg + 1;
    end
  end

  assign count = count_reg;

endmodule
